INSERT INTO [CodeBlockSource] ([CodeBlockId],[Source],[IsCS]) VALUES (
'f1b81939-fd57-47e2-acfa-05d1532ee3b4','
      Imports RDS.APC.RunTime.Processors
Imports System.Collections.Generic
Namespace CustomProcessor.DEPROC4.PreKCB 
    Public Class CodeBlock
        Implements ICodeBlock

       Public Sub Initialize(session As Session, codeBlockData As CodeBlockData) Implements ICodeBlock.Initialize
            ''Place your initialization code here, this will run on processor initialize only.
            ''session object is used to share data between code blocks execution.
            ''session.Get("<Session_Object_Name>") can be used to get existing session object, any write to this object will NOT persist.
            ''session.Set("<Session_Object_Name>") can be used to write/update/set existing session object, it will create an object with this name if it doesnt already present.
            ''codeBlock have HealthMessage and HealthStauts, write on these values will persist.     
       End Sub
       
       Public Sub Execute( session As Session, data As Data, codeBlockData As CodeBlockData) Implements ICodeBlock.Execute
           ''Place your execution code here, this will run on every execution.
           ''session object is used to share data between code blocks execution.
           ''session.Get("<Session_Object_Name>") can be used to get existing session object, any write to this object will NOT persist.
           ''session.Set("<Session_Object_Name>") can be used to write/update/set existing session object, it will create an object with this name if it doesnt already present.
